#include <signal.h>
#include <unistd.h>

void timeout_handler(int sig) {
 // Do nothing, just return to interrupt pause()
}

int main() {
 signal(SIGALRM, timeout_handler);

 alarm(5); // Set alarm for 5 seconds

 // This would block without alarm
 // With alarm, if it takes > 5 sec, we'll be interrupted
 char buffer[100];
 int n = read(STDIN_FILENO, buffer, sizeof(buffer));

 if (n < 0) {
 // Check if interrupted by alarm (timeout)
 }

 alarm(0); // Cancel any remaining alarm
 return 0;
}

unsigned int my_sleep(unsigned int seconds) {
 struct sigaction sa, old_sa;
 sigset_t mask, old_mask;
 unsigned int remaining = 0;

 // Set up handler for SIGALRM
 sa.sa_handler = alarm_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = 0;
 sigaction(SIGALRM, &sa, &old_sa);

 // Block SIGALRM
 sigemptyset(&mask);
 sigaddset(&mask, SIGALRM);
 sigprocmask(SIG_BLOCK, &mask, &old_mask);

 // Schedule alarm
 alarm(seconds);

 // Unblock SIGALRM and pause
 sigemptyset(&mask);
 sigaddset(&mask, SIGALRM);
 sigsuspend(&mask);

 // Get remaining time
 remaining = alarm(0);

 // Restore old handlers and mask
 sigaction(SIGALRM, &old_sa, NULL);
 sigprocmask(SIG_SETMASK, &old_mask, NULL);

 return remaining;
}

void alarm_handler(int sig) {
 // Does nothing, just returns
}

#include <sys/time.h>
#include <signal.h>

int count = 0;

void periodic_handler(int sig) {
 count++;
 printf("Timer fired %d times\n", count);
}

int main() {
 struct sigaction sa;
 struct itimerval timer;

 // Set up signal handler
 sa.sa_handler = periodic_handler;
 sa.sa_flags = SA_RESTART;
 sigemptyset(&sa.sa_mask);
 sigaction(SIGALRM, &sa, NULL);

 // Configure timer: fire every 2 seconds
 timer.it_value.tv_sec = 2; // First expiration after 2 seconds
 timer.it_value.tv_usec = 0;
 timer.it_interval.tv_sec = 2; // Subsequent expirations every 2 seconds
 timer.it_interval.tv_usec = 0;

 // Start the timer
 setitimer(ITIMER_REAL, &timer, NULL);

 // Do other work
 while (count < 5) {
 sleep(1);
 }

 // Disable timer
 timer.it_value.tv_sec = 0;
 timer.it_value.tv_usec = 0;
 timer.it_interval.tv_sec = 0;
 timer.it_interval.tv_usec = 0;
 setitimer(ITIMER_REAL, &timer, NULL);

 return 0;
}

#include <sys/time.h>
#include <signal.h>
#include <stdio.h>

static int profile_count = 0;

void prof_handler(int sig) {
 profile_count++;
}

void do_work() {
 // Simulate CPU-intensive work
 volatile long sum = 0;
 for (int i = 0; i < 1000000; i++) {
 sum += i;
 }
}

int main() {
 struct sigaction sa;
 struct itimerval timer, old_timer;

 sa.sa_handler = prof_handler;
 sa.sa_flags = 0;
 sigemptyset(&sa.sa_mask);
 sigaction(SIGPROF, &sa, NULL);

 // Profile every 10 milliseconds
 timer.it_value.tv_sec = 0;
 timer.it_value.tv_usec = 10000; // 10 ms
 timer.it_interval.tv_sec = 0;
 timer.it_interval.tv_usec = 10000;

 setitimer(ITIMER_PROF, &timer, &old_timer);

 // Perform work to be profiled
 do_work();

 // Get timer back
 setitimer(ITIMER_PROF, &old_timer, NULL);

 printf("Profile ticks: %d\n", profile_count);
 return 0;
}
